FOOD_CATEGORIES = {'fruit': ['apple', 'banana', 'orange', 'strawberry', 'blueberry', 'watermelon', 'pineapple', 'mango', 'grape', 'papaya', 'kiwi', 'peach', 'pear', 'cherry', 'pomegranate', 'guava', 'berries', 'melon', 'plum', 'apricot', 'fig', 'dates'], 'vegetable': ['tomato', 'carrot', 'broccoli', 'spinach', 'lettuce', 'cucumber', 'zucchini', 'pepper', 'cauliflower', 'celery', 'eggplant', 'potato', 'onion', 'garlic', 'mushroom', 'asparagus', 'bean', 'pea', 'corn', 'cabbage', 'kale', 'squash'], 'protein': ['salmon', 'chicken', 'beef', 'turkey', 'fish', 'tuna', 'shrimp', 'prawn', 'lamb', 'pork', 'egg', 'tofu', 'tempeh'], 'grain': ['rice', 'quinoa', 'oat', 'bread', 'pasta', 'noodle', 'barley', 'couscous', 'roti', 'chapati', 'paratha', 'naan', 'cereal', 'granola'], 'dairy': ['cheese', 'yogurt', 'milk', 'paneer', 'cottage', 'cream', 'butter'], 'legume': ['lentil', 'dal', 'chickpea', 'bean', 'hummus', 'edamame'], 'nut': ['almond', 'walnut', 'peanut', 'cashew', 'pistachio', 'seed', 'nut'], 'indian': ['idli', 'dosa', 'upma', 'poha', 'sambar', 'rasam', 'khichdi', 'biryani', 'curry', 'palak', 'paneer', 'tandoori', 'butter chicken']}

def get_food_image_url(food_name: str) -> str:
    if not food_name:
        return CATEGORY_IMAGES['default']
    food_lower = food_name.lower().strip()
    if food_lower in FOOD_IMAGE_URLS:
        return FOOD_IMAGE_URLS[food_lower]
    for key, url in FOOD_IMAGE_URLS.items():
        if key in food_lower or food_lower in key:
            return url
    food_words = food_lower.split()
    for word in food_words:
        if len(word) >= 3:
            for key, url in FOOD_IMAGE_URLS.items():
                if word in key.split() or word == key:
                    return url
    for category, keywords in FOOD_CATEGORIES.items():
        for keyword in keywords:
            if keyword in food_lower:
                return CATEGORY_IMAGES.get(category, CATEGORY_IMAGES['default'])
    return CATEGORY_IMAGES['default']

def get_category_image(category: str) -> str:
    return CATEGORY_IMAGES.get(category.lower(), CATEGORY_IMAGES['default'])